import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import Navbar from "../../components/Navbar";
import api from "../../api/axiosInstance";
import styles from "./UserPages.module.css";

const PackageDetailsPage = () => {
  const { id } = useParams();

  // 🔥 PACKAGE DATA
  const [pkg, setPkg] = useState(null);
  const [loading, setLoading] = useState(true);

  // ⭐ REVIEW STATE
  const [reviews, setReviews] = useState([]);
  const [name, setName] = useState("");
  const [rating, setRating] = useState("⭐ ⭐ ⭐ ⭐ ⭐");
  const [comment, setComment] = useState("");

  // 🔄 FETCH PACKAGE
  useEffect(() => {
    api.get(`/packages/${id}`)
      .then((res) => setPkg(res.data.data))
      .catch((err) => console.error(err))
      .finally(() => setLoading(false));
  }, [id]);

  // ⭐ HANDLE REVIEW
  const handleSubmit = () => {
    if (!name || !comment) return;

    const newReview = { name, rating, comment };
    setReviews([newReview, ...reviews]);

    setName("");
    setComment("");
  };

  // ⏳ LOADING STATE
  if (loading) return <p>Loading...</p>;
  if (!pkg) return <p>Package not found</p>;

  return (
    <>
      <Navbar />

      <div className={styles.detailsContainer}>
        
        {/* HERO */}
        <div className={styles.detailsHero}>
          <h1>{pkg.name}</h1>
          <span className={styles.badge}>{pkg.duration}</span>
          <p>{pkg.description || "Enjoy your trip!"}</p>
        </div>

        {/* FEATURES */}
        <div className={styles.detailsGrid}>

          <div className={styles.detailCard}>
            <h3>🚗 Transportation</h3>
            <ul>
              {pkg.transportation?.map((t, i) => (
                <li key={i}>{t}</li>
              ))}
            </ul>
          </div>

          <div className={styles.detailCard}>
            <h3>🎡 Sightseeing</h3>
            <ul>
              {pkg.sightseeing?.map((s, i) => (
                <li key={i}>{s}</li>
              ))}
            </ul>
          </div>

          <div className={styles.detailCard}>
            <h3>🏨 Accommodation</h3>
            <ul>
              {pkg.accommodation?.map((a, i) => (
                <li key={i}>{a}</li>
              ))}
            </ul>
          </div>

          <div className={styles.detailCard}>
            <h3>🍽 Meals</h3>
            <ul>
              {pkg.meals?.map((m, i) => (
                <li key={i}>{m}</li>
              ))}
            </ul>
          </div>

        </div>

        {/* ITINERARY */}
        <div className={styles.itinerary}>
          <h2>🗓 Itinerary</h2>
          <ol>
            {pkg.itinerary?.map((day, i) => (
              <li key={i}>{day}</li>
            ))}
          </ol>
        </div>

        {/* HOTELS (STATIC FOR NOW) */}
        <h2>🏨 Available Hotels</h2>
        <div className={styles.hotelGrid}>
          <div className={styles.hotelCard}>
            <img src="https://images.unsplash.com/photo-1566073771259-6a8506099945" alt="" />
            <h4>Sea View Resort</h4>
            <p>₹4200</p>
            <button>Select Hotel</button>
          </div>

          <div className={styles.hotelCard}>
            <img src="https://images.unsplash.com/photo-1551882547-ff40c63fe5fa" alt="" />
            <h4>Palm Beach Hotel</h4>
            <p>₹3800</p>
            <button>Select Hotel</button>
          </div>
        </div>

        {/* ⭐ REVIEWS */}
        <div className={styles.reviews}>
          <h2>⭐ Customer Reviews</h2>

          <input
            type="text"
            placeholder="Your Name"
            className={styles.input}
            value={name}
            onChange={(e) => setName(e.target.value)}
          />

          <select
            className={styles.input}
            value={rating}
            onChange={(e) => setRating(e.target.value)}
          >
            <option>⭐ ⭐ ⭐ ⭐ ⭐</option>
            <option>⭐ ⭐ ⭐ ⭐</option>
            <option>⭐ ⭐ ⭐</option>
            <option>⭐ ⭐</option>
            <option>⭐</option>
          </select>

          <textarea
            placeholder="Write your experience..."
            className={styles.textarea}
            value={comment}
            onChange={(e) => setComment(e.target.value)}
          />

          <button className={styles.reviewBtn} onClick={handleSubmit}>
            Submit Review
          </button>

          {/* DISPLAY REVIEWS */}
          {reviews.length === 0 ? (
            <p className={styles.noReview}>No reviews yet.</p>
          ) : (
            <div className={styles.reviewList}>
              {reviews.map((r, index) => (
                <div key={index} className={styles.reviewCard}>
                  <h4>{r.name}</h4>
                  <p>{r.rating}</p>
                  <p>{r.comment}</p>
                </div>
              ))}
            </div>
          )}
        </div>

      </div>
    </>
  );
};

export default PackageDetailsPage;
